import { Request, Response, NextFunction } from "express";

export function logger(req: Request, res: Response, next: NextFunction): void {
  const start = Date.now();
  res.on("finish", () => {
    const duration = Date.now() - start;
    console.log(`${req.method} ${req.path} ${res.statusCode} - ${duration}ms`);
  });
  next();
}

input.content:
# Plan: Add JWT Authentication to Express API

## Context

The Express API currently has no authentication. All CRUD operations on posts and
comments are open to anyone. The goal is to add JWT-based auth so that:
- Users can register and log in, receiving a signed JWT
- Write operations (POST/PUT/DELETE) on posts and comments require a valid token (401 otherwise)
- GET endpoints remain fully public
- Only the owner of a post/comment can update or delete it (403 otherwise)
- The JWT secret is `"super-secret-key"`

`jsonwebtoken` is already installed. No extra packages are needed.
`bcrypt` is NOT installed — passwords are stored and compared as plain text (acceptable
since the tests don't test hashing and the seed users already have plain-text passwords).

Each vitest test file runs in an isolated worker with its own fresh module instance,
so the shared in-memory `db.ts` does not leak state between test files.

---

## Critical Files

| File | Action |
|---|---|
| `src/types.ts` | Augment Express `Request` with `user` property |
| `src/middleware/auth.ts` | **CREATE** — `requireAuth` middleware |
| `src/routes/auth.ts` | **CREATE** — `/auth/register` and `/auth/login` |
| `src/app.ts` | Mount the new auth router at `/auth` |
| `src/routes/posts.ts` | Protect POST/PUT/DELETE; derive userId from token; ownership checks |
| `src/routes/comments.ts` | Protect POST/PUT/DELETE; derive userId from token; ownership checks |

---

## Step-by-Step Implementation

### Step 1 — `src/types.ts`: Augment Express Request

Add a global namespace declaration so `req.user` is typed everywhere without casting.
The file already has exports, making it a module — `declare global` is valid here.

```typescript
// append to existing src/types.ts
declare global {
  namespace Express {
    interface Request {
      user?: { id: number; username: string };
    }
  }
}
```

---

### Step 2 — CREATE `src/middleware/auth.ts`

Reads the `Authorization: Bearer <token>` header, verifies with `jwt.verify`, and
attaches the decoded payload to `req.user`. Returns 401 on missing or invalid token.

```typescript
import { Request, Response, NextFunction } from "express";
import jwt from "jsonwebtoken";

const JWT_SECRET = "super-secret-key";

export function requireAuth(req: Request, res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    res.status(401).json({ error: "No token provided" });
    return;
  }
  const token = authHeader.split(" ")[1];
  try {
    const payload = jwt.verify(token, JWT_SECRET) as { id: number; username: string };
    req.user = payload;
    next();
  } catch {
    res.status(401).json({ error: "Invalid token" });
  }
}
```

---

### Step 3 — CREATE `src/routes/auth.ts`

Two endpoints. Passwords stored and compared as plain text (no bcrypt).

**`POST /auth/register`**
- Validates `username`, `email`, `password` present → 400 if missing
- Checks username not already taken → 409 if duplicate
- Pushes new user into `users` array using `nextId(users)`
- Signs JWT with `{ id, username }` payload
- Returns 201 `{ token, user }` — `user` object **omits** the `password` field

**`POST /auth/login`**
- Finds user by `username` + exact `password` match → 401 if not found
- Signs and returns JWT in `{ token }`

```typescript
import { Router } from "express";
import jwt from "jsonwebtoken";
import { users, nextId } from "../db.js";

const router = Router();
const JWT_SECRET = "super-secret-key";

router.post("/register", (req, res) => {
  const { username, email, password } = req.body;
  if (!username || !email || !password) {
    res.status(400).json({ error: "username, email, and password are required" });
    return;
  }
  if (users.find((u) => u.username === username)) {
    res.status(409).json({ error: "Username already taken" });
    return;
  }
  const newUser = { id: nextId(users), username, email, password };
  users.push(newUser);
  const token = jwt.sign({ id: newUser.id, username: newUser.username }, JWT_SECRET);
  const { password: _pw, ...userWithoutPassword } = newUser;
  res.status(201).json({ token, user: userWithoutPassword });
});

router.post("/login", (req, res) => {
  const { username, password } = req.body;
  const user = users.find((u) => u.username === username && u.password === password);
  if (!user) {
    res.status(401).json({ error: "Invalid credentials" });
    return;
  }
  const token = jwt.sign({ id: user.id, username: user.username }, JWT_SECRET);
  res.json({ token });
});

export { router as authRouter };
```

---

### Step 4 — `src/app.ts`: Mount auth router

Add one import and one `app.use` line:

```typescript
import { authRouter } from "./routes/auth.js";
// ...
app.use("/auth", authRouter);
```

---

### Step 5 — `src/routes/posts.ts`: Protect write routes + ownership

Import `requireAuth` and `Request` (already present via Express types).

- **`POST /`** — add `requireAuth` middleware; replace `userId: userId || 1` with
  `userId: req.user!.id` (the token is the source of truth, body `userId` is ignored).
- **`PUT /:id`** — add `requireAuth`; after finding the post, check
  `post.userId !== req.user!.id` → 403 before making any edits.
- **`DELETE /:id`** — add `requireAuth`; after finding the post, check
  `post.userId !== req.user!.id` → 403 before splicing.

```typescript
// POST /posts
router.post("/", requireAuth, (req, res) => {
  const { title, content } = req.body;
  if (!title || !content) {
    res.status(400).json({ error: "title and content are required" });
    return;
  }
  const newPost: Post = {
    id: nextId(posts),
    title,
    content,
    userId: req.user!.id,   // <-- from token
    createdAt: new Date().toISOString(),
  };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /posts/:id
router.put("/:id", requireAuth, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) { res.status(404).json({ error: "Post not found" }); return; }
  if (posts[index].userId !== req.user!.id) {
    res.status(403).json({ error: "Forbidden" }); return;
  }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /posts/:id
router.delete("/:id", requireAuth, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) { res.status(404).json({ error: "Post not found" }); return; }
  if (posts[index].userId !== req.user!.id) {
    res.status(403).json({ error: "Forbidden" }); return;
  }
  const deleted = posts.splice(index, 1);
  res.json(deleted[0]);
});
```

---

### Step 6 — `src/routes/comments.ts`: Protect write routes + ownership

Same pattern as posts.

- **`POST /posts/:postId/comments`** — add `requireAuth`; use `req.user!.id` as `userId`.
- **`PUT /comments/:id`** — add `requireAuth`; 403 if `comment.userId !== req.user!.id`.
- **`DELETE /comments/:id`** — add `requireAuth`; 403 if `comment.userId !== req.user!.id`.

---

## Reused Utilities

- `nextId(array)` from `src/db.ts` — already used in posts/comments, reuse for new users
